+      });
+
+      for (const k of K_VALUES) {
+        bench(`search k=${k}`, async () => {
+          const query = queryVectors[Math.floor(Math.random() * queryVectors.length)];
+          backend.search(query, k);
+        }, {
+          warmupIterations: 10,
+          iterations: 100
+        });
+      }
+
