+  });
+
+  const stats = causal.getStats();
+  console.log('✅ v1 CausalRecall works:', typeof stats === 'object');
+
+  db.close();
+})();
+"
+
+echo ""
+echo "=========================================="
+echo "✅ ALL v1 API COMPATIBILITY TESTS PASSED"
+echo "=========================================="

